    @Override
    public void displayInfo() {
        System.out.println("User Name: " + userName);
        System.out.println("User Password: " + password);
        System.out.println("Contact information: " + contactInfo);
        System.out.println("is user admin: " + isAdmin + "\n");
    }
}

